	textEdit.BeginComplexOperation()
	textEdit.BeginMulticaretEdit()
	for i := 0; i < textEdit.GetCaretCount(); i++ {
		if textEdit.MulticaretEditIgnoreCaret(i) {
			continue
		}
		// Logic here.
	}
	textEdit.EndMulticaretEdit()
	textEdit.EndComplexOperation()

